#!/usr/bin/env node
/**
 * Published smoke test for the Client Portal public access runtime.
 *
 * The script expects a fixture JSON generated by client-portal-smoke-fixture.php
 * and validates the real published URL with Playwright.
 */

import { createRequire } from 'node:module';
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import { pathToFileURL } from 'node:url';

const breakpoints = [375, 600, 840, 1200, 1920];

function parseArgs(argv) {
    const options = {};

    for (let index = 0; index < argv.length; index += 1) {
        const arg = argv[index];

        if (!arg.startsWith('--')) {
            continue;
        }

        const [rawKey, inlineValue] = arg.slice(2).split('=', 2);
        const key = rawKey.trim();

        if (!key) {
            continue;
        }

        if (typeof inlineValue !== 'undefined') {
            options[key] = inlineValue;
            continue;
        }

        const next = argv[index + 1];
        if (next && !next.startsWith('--')) {
            options[key] = next;
            index += 1;
            continue;
        }

        options[key] = '1';
    }

    return options;
}

function loadPlaywright() {
    const candidates = [
        import.meta.url,
        pathToFileURL(path.join(process.cwd(), '.playwright-runtime', 'package.json')).href,
    ];

    for (const candidate of candidates) {
        try {
            return createRequire(candidate)('playwright');
        } catch (error) {
            if (error && error.code !== 'MODULE_NOT_FOUND') {
                throw error;
            }
        }
    }

    throw new Error('Playwright nao foi encontrado. Instale ou exponha o pacote em .playwright-runtime/node_modules.');
}

function requireString(value, name) {
    if (typeof value !== 'string' || value.trim() === '') {
        throw new Error(`Fixture invalida: ${name} ausente.`);
    }

    return value.trim();
}

function buildFixture(rawFixture) {
    return {
        tag: requireString(rawFixture.tag, 'tag'),
        portalUrl: requireString(rawFixture.portalUrl, 'portalUrl'),
        email: requireString(rawFixture.email, 'email'),
        resetEmail: typeof rawFixture.resetEmail === 'string' ? rawFixture.resetEmail.trim() : '',
        antiEnumEmail: requireString(rawFixture.antiEnumEmail, 'antiEnumEmail'),
        password: requireString(rawFixture.password, 'password'),
        newPassword: requireString(rawFixture.newPassword, 'newPassword'),
        magicUrl: requireString(rawFixture.magicUrl, 'magicUrl'),
        validResetUrl: requireString(rawFixture.validResetUrl, 'validResetUrl'),
        invalidResetUrl: requireString(rawFixture.invalidResetUrl, 'invalidResetUrl'),
        expiredResetUrl: requireString(rawFixture.expiredResetUrl, 'expiredResetUrl'),
    };
}

function publicFixtureSummary(fixture) {
    return {
        tag: fixture.tag,
        email: fixture.email,
        resetEmail: fixture.resetEmail,
        antiEnumEmail: fixture.antiEnumEmail,
        portalUrl: fixture.portalUrl,
    };
}

function createRunState(label) {
    return {
        label,
        pageErrors: [],
        consoleErrors: [],
        consoleWarnings: [],
        responses: [],
    };
}

function bindPageEvents(page, state) {
    page.on('pageerror', (error) => {
        state.pageErrors.push(error && error.message ? error.message : String(error));
    });

    page.on('console', (message) => {
        const entry = `${message.type()}: ${message.text()}`;

        if (message.type() === 'error') {
            state.consoleErrors.push(entry);
        } else if (message.type() === 'warning') {
            state.consoleWarnings.push(entry);
        }
    });
}

async function newInstrumentedPage(browser, label, width = 1200) {
    const context = await browser.newContext({
        viewport: { width, height: 920 },
        ignoreHTTPSErrors: true,
    });
    const page = await context.newPage();
    const state = createRunState(label);
    bindPageEvents(page, state);

    return { context, page, state };
}

async function waitForPortalPublicShell(page) {
    await page.waitForSelector('[data-dps-access-root]', { timeout: 15000 });
    await page.waitForSelector('script[src*="client-portal-access.js"]', { state: 'attached', timeout: 15000 });
}

async function waitForAuthenticatedPortal(page) {
    await page.waitForSelector('.dps-client-portal', { timeout: 20000 });
    await page.waitForSelector('script[src*="client-portal.js"]', { state: 'attached', timeout: 15000 });
}

async function collectMetrics(page) {
    return page.evaluate(() => {
        const scripts = Array.from(document.scripts)
            .map((script) => script.src)
            .filter(Boolean);
        const accessRoot = document.querySelector('[data-dps-access-root]');
        const cta = Array.from(document.querySelectorAll('button'))
            .find((button) => /criar ou redefinir senha/i.test(button.textContent || ''));
        const ctaRect = cta ? cta.getBoundingClientRect() : null;

        return {
            url: window.location.href,
            title: document.title,
            overflowX: Math.max(
                0,
                document.documentElement.scrollWidth - document.documentElement.clientWidth,
                document.body ? document.body.scrollWidth - document.body.clientWidth : 0
            ),
            accessRoot: Boolean(accessRoot),
            accessScript: scripts.filter((src) => src.includes('/client-portal-access.js')),
            authenticatedScript: scripts.filter((src) => src.includes('/client-portal.js')),
            authCss: Array.from(document.styleSheets)
                .map((sheet) => sheet.href || '')
                .filter((href) => href.includes('/client-portal-auth.css')),
            cta: ctaRect
                ? {
                    text: (cta.textContent || '').trim(),
                    width: Math.round(ctaRect.width),
                    height: Math.round(ctaRect.height),
                }
                : null,
        };
    });
}

async function collectAuthenticatedMetrics(page) {
    return page.evaluate(() => {
        const scripts = Array.from(document.scripts)
            .map((script) => script.src)
            .filter(Boolean);
        const tabs = Array.from(document.querySelectorAll('.dps-portal-tabs__link[data-tab]'))
            .map((tab) => ({
                tab: tab.getAttribute('data-tab'),
                label: (tab.textContent || '').trim().replace(/\s+/g, ' '),
            }));

        return {
            url: window.location.href,
            overflowX: Math.max(
                0,
                document.documentElement.scrollWidth - document.documentElement.clientWidth,
                document.body ? document.body.scrollWidth - document.body.clientWidth : 0
            ),
            portalPresent: Boolean(document.querySelector('.dps-client-portal')),
            tabsCount: tabs.length,
            tabs,
            activeTab: document.querySelector('.dps-portal-tabs__link.is-active[data-tab]')?.getAttribute('data-tab') || '',
            heading: (document.querySelector('.dps-portal-title')?.textContent || '').trim(),
            accessScript: scripts.filter((src) => src.includes('/client-portal-access.js')),
            authenticatedScript: scripts.filter((src) => src.includes('/client-portal.js')),
        };
    });
}

async function collectResetState(page) {
    return page.evaluate(() => {
        const notices = Array.from(document.querySelectorAll('.dps-signature-notice'))
            .map((notice) => ({
                className: notice.className,
                title: (notice.querySelector('.dps-signature-notice__title')?.textContent || '').trim(),
                text: (notice.querySelector('.dps-signature-notice__text')?.textContent || '').trim(),
            }));
        const panelTitle = (document.querySelector('.dps-portal-reset-card .dps-signature-panel__title')?.textContent || '').trim();

        return {
            url: window.location.href,
            overflowX: Math.max(
                0,
                document.documentElement.scrollWidth - document.documentElement.clientWidth,
                document.body ? document.body.scrollWidth - document.body.clientWidth : 0
            ),
            notices,
            panelTitle,
            hasResetForm: Boolean(document.querySelector('form input[name="dps_portal_password_reset_submit"]')),
            toggleCount: document.querySelectorAll('[data-dps-password-toggle]').length,
        };
    });
}

function assertCondition(condition, message) {
    if (!condition) {
        throw new Error(message);
    }
}

function assertNoPageErrors(state) {
    assertCondition(state.pageErrors.length === 0, `${state.label}: pageErrors nao esta vazio.`);
}

function adminAjaxAction(actionName) {
    return (response) => {
        const request = response.request();
        const postData = request.postData() || '';

        return response.url().includes('admin-ajax.php') && postData.includes(`action=${actionName}`);
    };
}

async function validateBreakpoints(browser, fixture, outputDir) {
    const results = {};

    for (const width of breakpoints) {
        const { context, page, state } = await newInstrumentedPage(browser, `public-shell-${width}`, width);
        await page.goto(fixture.portalUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
        await waitForPortalPublicShell(page);
        const metrics = await collectMetrics(page);
        const screenshot = path.join(outputDir, `portal-public-shell-${width}.png`);
        await page.screenshot({ path: screenshot, fullPage: true });

        assertNoPageErrors(state);
        assertCondition(metrics.overflowX === 0, `public-shell-${width}: overflowX=${metrics.overflowX}`);
        assertCondition(metrics.accessScript.length > 0, `public-shell-${width}: client-portal-access.js nao foi carregado.`);
        assertCondition(metrics.authenticatedScript.length === 0, `public-shell-${width}: client-portal.js nao deve carregar no runtime publico.`);
        assertCondition(metrics.cta && /criar ou redefinir senha/i.test(metrics.cta.text), `public-shell-${width}: CTA de reset nao encontrado.`);

        results[String(width)] = {
            metrics,
            pageErrors: state.pageErrors,
            consoleErrors: state.consoleErrors,
            consoleWarnings: state.consoleWarnings,
            screenshot,
        };

        await context.close();
    }

    return results;
}

async function validatePasswordAccess(browser, fixture, outputDir) {
    const { context, page, state } = await newInstrumentedPage(browser, 'password-login');
    await page.goto(fixture.portalUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForPortalPublicShell(page);
    await page.fill('#dps-portal-password-email', fixture.email);
    await page.fill('#dps-portal-password', fixture.password);
    await Promise.all([
        page.waitForLoadState('domcontentloaded', { timeout: 20000 }).catch(() => undefined),
        page.locator('[data-dps-password-login-form] button[type="submit"]').click(),
    ]);
    await waitForAuthenticatedPortal(page);
    await page.waitForFunction(() => !window.location.href.includes('portal_auth_error'), null, { timeout: 10000 }).catch(() => undefined);

    const metrics = await collectAuthenticatedMetrics(page);
    const screenshot = path.join(outputDir, 'portal-password-login-success-1200.png');
    await page.screenshot({ path: screenshot, fullPage: true });

    assertNoPageErrors(state);
    assertCondition(metrics.portalPresent, 'password-login: portal autenticado nao apareceu.');
    assertCondition(metrics.tabsCount > 0, 'password-login: tabs autenticadas nao apareceram.');
    assertCondition(metrics.overflowX === 0, `password-login: overflowX=${metrics.overflowX}`);
    assertCondition(metrics.authenticatedScript.length > 0, 'password-login: client-portal.js nao carregou no runtime autenticado.');
    assertCondition(metrics.accessScript.length === 0, 'password-login: client-portal-access.js nao deve carregar no runtime autenticado.');

    await context.close();

    return {
        metrics,
        pageErrors: state.pageErrors,
        consoleErrors: state.consoleErrors,
        consoleWarnings: state.consoleWarnings,
        screenshot,
    };
}

async function validateMagicLogin(browser, fixture, outputDir) {
    const { context, page, state } = await newInstrumentedPage(browser, 'magic-login');
    await page.goto(fixture.magicUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForAuthenticatedPortal(page);
    await page.waitForFunction(() => !window.location.href.includes('dps_token'), null, { timeout: 10000 }).catch(() => undefined);

    const metrics = await collectAuthenticatedMetrics(page);
    const screenshot = path.join(outputDir, 'portal-magic-login-success-1200.png');
    await page.screenshot({ path: screenshot, fullPage: true });

    assertNoPageErrors(state);
    assertCondition(metrics.portalPresent, 'magic-login: portal autenticado nao apareceu.');
    assertCondition(metrics.tabsCount > 0, 'magic-login: tabs autenticadas nao apareceram.');
    assertCondition(metrics.authenticatedScript.length > 0, 'magic-login: client-portal.js nao carregou no runtime autenticado.');
    assertCondition(metrics.accessScript.length === 0, 'magic-login: client-portal-access.js nao deve carregar no runtime autenticado.');

    await context.close();

    return {
        metrics,
        pageErrors: state.pageErrors,
        consoleErrors: state.consoleErrors,
        consoleWarnings: state.consoleWarnings,
        screenshot,
    };
}

async function validatePublicRequests(browser, fixture, outputDir) {
    const { context, page, state } = await newInstrumentedPage(browser, 'public-requests');
    await page.goto(fixture.portalUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForPortalPublicShell(page);

    await page.fill('#dps-portal-password-email', fixture.antiEnumEmail);
    const passwordResponsePromise = page.waitForResponse(adminAjaxAction('dps_request_portal_password_access'), { timeout: 20000 });
    await page.locator('[data-dps-password-access-trigger]').click();
    const passwordResponse = await passwordResponsePromise;
    const passwordJson = await passwordResponse.json();
    await page.waitForSelector('[data-dps-password-feedback]:not([hidden])', { timeout: 10000 });
    const passwordFeedback = await page.locator('[data-dps-password-feedback]').innerText();
    const passwordScreenshot = path.join(outputDir, 'portal-password-access-anti-enumeration-1200.png');
    await page.screenshot({ path: passwordScreenshot, fullPage: true });

    assertCondition(passwordResponse.status() === 200, `password-access: status=${passwordResponse.status()}`);
    assertCondition(Boolean(passwordJson.success), 'password-access: resposta anti-enumeration nao retornou success=true.');
    assertCondition(/se este e-mail estiver cadastrado/i.test(passwordFeedback), 'password-access: feedback anti-enumeration inesperado.');

    await page.locator('#dps-auth-tab-magic').click();
    await page.fill('#dps-portal-magic-email', fixture.email);
    const magicResponsePromise = page.waitForResponse(adminAjaxAction('dps_request_access_link_by_email'), { timeout: 20000 });
    await page.locator('[data-dps-access-form="magic-link"] button[type="submit"]').click();
    const magicResponse = await magicResponsePromise;
    const magicJson = await magicResponse.json();
    await page.waitForSelector('[data-dps-form-feedback]:not([hidden])', { timeout: 10000 });
    const magicFeedback = await page.locator('[data-dps-form-feedback]').innerText();
    const magicScreenshot = path.join(outputDir, 'portal-magic-link-request-1200.png');
    await page.screenshot({ path: magicScreenshot, fullPage: true });

    assertNoPageErrors(state);
    assertCondition(magicResponse.status() === 200, `magic-request: status=${magicResponse.status()}`);
    assertCondition(Boolean(magicJson.success), 'magic-request: resposta nao retornou success=true.');
    assertCondition(/link enviado com sucesso/i.test(magicFeedback), 'magic-request: feedback inesperado.');

    await context.close();

    return {
        passwordAccess: {
            status: passwordResponse.status(),
            ok: passwordResponse.ok(),
            response: passwordJson,
            feedback: passwordFeedback,
            screenshot: passwordScreenshot,
        },
        magicRequest: {
            status: magicResponse.status(),
            ok: magicResponse.ok(),
            response: magicJson,
            feedback: magicFeedback,
            screenshot: magicScreenshot,
        },
        pageErrors: state.pageErrors,
        consoleErrors: state.consoleErrors,
        consoleWarnings: state.consoleWarnings,
    };
}

async function validateResetState(browser, label, url, outputDir, expected) {
    const { context, page, state } = await newInstrumentedPage(browser, label);
    await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForPortalPublicShell(page);
    const metrics = await collectResetState(page);
    const screenshot = path.join(outputDir, `portal-${label}-1200.png`);
    await page.screenshot({ path: screenshot, fullPage: true });

    assertNoPageErrors(state);
    assertCondition(metrics.overflowX === 0, `${label}: overflowX=${metrics.overflowX}`);

    if (expected === 'invalid') {
        assertCondition(!metrics.hasResetForm, `${label}: formulario nao deveria aparecer para link invalido.`);
        assertCondition(metrics.notices.some((notice) => /invalido/i.test(notice.title)), `${label}: notice invalido nao encontrado.`);
    } else if (expected === 'expired') {
        assertCondition(!metrics.hasResetForm, `${label}: formulario nao deveria aparecer para link expirado.`);
        assertCondition(metrics.notices.some((notice) => /expirado/i.test(notice.title)), `${label}: notice expirado nao encontrado.`);
    } else if (expected === 'valid') {
        assertCondition(metrics.hasResetForm, `${label}: formulario deveria aparecer para link valido.`);
        assertCondition(metrics.toggleCount === 2, `${label}: esperado toggleCount=2, recebido ${metrics.toggleCount}.`);
    }

    await context.close();

    return {
        metrics,
        pageErrors: state.pageErrors,
        consoleErrors: state.consoleErrors,
        consoleWarnings: state.consoleWarnings,
        screenshot,
    };
}

async function validateValidResetSubmit(browser, fixture, outputDir) {
    const { context, page, state } = await newInstrumentedPage(browser, 'reset-valid-submit');
    await page.goto(fixture.validResetUrl, { waitUntil: 'domcontentloaded', timeout: 30000 });
    await waitForPortalPublicShell(page);
    await page.fill('#dps-portal-new-password', fixture.newPassword);
    await page.fill('#dps-portal-confirm-password', fixture.newPassword);
    await Promise.all([
        page.waitForLoadState('domcontentloaded', { timeout: 20000 }).catch(() => undefined),
        page.locator('form button[type="submit"]').click(),
    ]);
    await waitForAuthenticatedPortal(page);

    const metrics = await collectAuthenticatedMetrics(page);
    const screenshot = path.join(outputDir, 'portal-reset-valid-success-1200.png');
    await page.screenshot({ path: screenshot, fullPage: true });

    assertNoPageErrors(state);
    assertCondition(metrics.portalPresent, 'reset-valid-submit: portal autenticado nao apareceu apos salvar senha.');
    assertCondition(metrics.tabsCount > 0, 'reset-valid-submit: tabs autenticadas nao apareceram.');
    assertCondition(metrics.overflowX === 0, `reset-valid-submit: overflowX=${metrics.overflowX}`);

    await context.close();

    return {
        metrics,
        pageErrors: state.pageErrors,
        consoleErrors: state.consoleErrors,
        consoleWarnings: state.consoleWarnings,
        screenshot,
    };
}

async function main() {
    const options = parseArgs(process.argv.slice(2));
    const fixturePath = options.fixture;

    if (!fixturePath) {
        throw new Error('Informe --fixture com o JSON gerado pelo WP-CLI.');
    }

    const outputDir = options['output-dir'] || path.join('docs', 'screenshots', new Date().toISOString().slice(0, 10), 'client-portal-public-smoke');
    const headless = options.headless === 'false' || options.headed === '1' ? false : true;
    const rawFixture = JSON.parse(await readFile(fixturePath, 'utf8'));
    const fixture = buildFixture(rawFixture);
    const { chromium } = loadPlaywright();

    await mkdir(outputDir, { recursive: true });

    const browser = await chromium.launch({ headless });
    const result = {
        auditedAt: new Date().toISOString(),
        sourceOfTruth: [
            'docs/visual/FRONTEND_DESIGN_INSTRUCTIONS.md',
            'docs/visual/VISUAL_STYLE_GUIDE.md',
        ],
        fixture: publicFixtureSummary(fixture),
        breakpoints: {},
        flows: {},
        status: 'running',
    };

    try {
        result.breakpoints = await validateBreakpoints(browser, fixture, outputDir);
        result.flows.publicRequests = await validatePublicRequests(browser, fixture, outputDir);
        result.flows.passwordLogin = await validatePasswordAccess(browser, fixture, outputDir);
        result.flows.magicLogin = await validateMagicLogin(browser, fixture, outputDir);
        result.flows.resetInvalid = await validateResetState(browser, 'reset-invalid', fixture.invalidResetUrl, outputDir, 'invalid');
        result.flows.resetExpired = await validateResetState(browser, 'reset-expired', fixture.expiredResetUrl, outputDir, 'expired');
        result.flows.resetValidScreen = await validateResetState(browser, 'reset-valid-screen', fixture.validResetUrl, outputDir, 'valid');
        result.flows.resetValidSubmit = await validateValidResetSubmit(browser, fixture, outputDir);
        result.status = 'passed';
    } catch (error) {
        result.status = 'failed';
        result.error = error && error.stack ? error.stack : String(error);
        throw error;
    } finally {
        await browser.close();
        const resultPath = path.join(outputDir, 'portal-client-public-smoke-result.json');
        result.resultPath = resultPath;
        await writeFile(resultPath, `${JSON.stringify(result, null, 2)}\n`, 'utf8');
        process.stdout.write(`${JSON.stringify({ status: result.status, resultPath }, null, 2)}\n`);
    }
}

main().catch((error) => {
    process.stderr.write(`${error && error.stack ? error.stack : String(error)}\n`);
    process.exitCode = 1;
});
